const decoder=new TextDecoder();const encoder=new TextEncoder();export class NoSuchMethodError extends Error{constructor(methodName){super(`Method "${methodName}" does not exist on impl.`);}}
export class MethodNotSupportedError extends Error{constructor(methodName){super(`Method "${methodName}" is not supported on this impl.`);}}
export class ImplAlreadySetError extends Error{constructor(){super(`Implementation already set.`);}}
function assertValidFileOrDirPath(fileOrDirPath){if(!fileOrDirPath||(!(fileOrDirPath instanceof URL)&&typeof fileOrDirPath!=="string")){throw new TypeError("Path must be a non-empty string or URL.");}}
function assertValidFileContents(contents){if(typeof contents!=="string"&&!(contents instanceof ArrayBuffer)&&!ArrayBuffer.isView(contents)){throw new TypeError("File contents must be a string, ArrayBuffer, or ArrayBuffer view.",);}}
function toUint8Array(contents){if(contents instanceof Uint8Array){return contents;}
if(typeof contents==="string"){return encoder.encode(contents);}
if(contents instanceof ArrayBuffer){return new Uint8Array(contents);}
if(ArrayBuffer.isView(contents)){const bytes=contents.buffer.slice(contents.byteOffset,contents.byteOffset+contents.byteLength,);return new Uint8Array(bytes);}
throw new TypeError("Invalid contents type. Expected string or ArrayBuffer.",);}
export class LogEntry{type;data;timestamp=Date.now();constructor(type,data){this.type=type;this.data=data;}}
export class Hfs{#baseImpl;#impl;#logs=new Map();constructor({impl}){this.#baseImpl=impl;this.#impl=impl;}#log(methodName,...args){for(const logs of this.#logs.values()){logs.push(new LogEntry("call",{methodName,args}));}}
logStart(name){if(!name||typeof name!=="string"){throw new TypeError("Log name must be a non-empty string.");}
if(this.#logs.has(name)){throw new Error(`Log "${name}" already exists.`);}
this.#logs.set(name,[]);}
logEnd(name){if(this.#logs.has(name)){const logs=this.#logs.get(name);this.#logs.delete(name);return logs;}
throw new Error(`Log "${name}" does not exist.`);}
isBaseImpl(){return this.#impl===this.#baseImpl;}
setImpl(impl){this.#log("implSet",impl);if(this.#impl!==this.#baseImpl){throw new ImplAlreadySetError();}
this.#impl=impl;}
resetImpl(){this.#log("implReset");this.#impl=this.#baseImpl;}#assertImplMethod(methodName){if(typeof this.#impl[methodName]!=="function"){throw new NoSuchMethodError(methodName);}}#assertImplMethodAlt(methodName,targetMethodName){if(typeof this.#impl[methodName]!=="function"){throw new MethodNotSupportedError(targetMethodName);}}#callImplMethod(methodName,...args){this.#log(methodName,...args);this.#assertImplMethod(methodName);return this.#impl[methodName](...args);}#callImplMethodWithoutLog(methodName,...args){this.#assertImplMethod(methodName);return this.#impl[methodName](...args);}#callImplMethodAlt(methodName,targetMethodName,...args){this.#log(targetMethodName,...args);this.#assertImplMethodAlt(methodName,targetMethodName);return this.#impl[methodName](...args);}
async text(filePath){assertValidFileOrDirPath(filePath);const result=await this.#callImplMethodAlt("bytes","text",filePath);return result?decoder.decode(result):undefined;}
async json(filePath){assertValidFileOrDirPath(filePath);const result=await this.#callImplMethodAlt("bytes","json",filePath);return result?JSON.parse(decoder.decode(result)):undefined;}
async arrayBuffer(filePath){assertValidFileOrDirPath(filePath);const result=await this.#callImplMethodAlt("bytes","arrayBuffer",filePath,);return result?.buffer;}
async bytes(filePath){assertValidFileOrDirPath(filePath);return this.#callImplMethod("bytes",filePath);}
async write(filePath,contents){assertValidFileOrDirPath(filePath);assertValidFileContents(contents);this.#log("write",filePath,contents);let value=toUint8Array(contents);return this.#callImplMethodWithoutLog("write",filePath,value);}
async append(filePath,contents){assertValidFileOrDirPath(filePath);assertValidFileContents(contents);this.#log("append",filePath,contents);let value=toUint8Array(contents);return this.#callImplMethodWithoutLog("append",filePath,value);}
async isFile(filePath){assertValidFileOrDirPath(filePath);return this.#callImplMethod("isFile",filePath);}
async isDirectory(dirPath){assertValidFileOrDirPath(dirPath);return this.#callImplMethod("isDirectory",dirPath);}
async createDirectory(dirPath){assertValidFileOrDirPath(dirPath);return this.#callImplMethod("createDirectory",dirPath);}
async delete(filePath){assertValidFileOrDirPath(filePath);return this.#callImplMethod("delete",filePath);}
async deleteAll(dirPath){assertValidFileOrDirPath(dirPath);return this.#callImplMethod("deleteAll",dirPath);}
async*list(dirPath){assertValidFileOrDirPath(dirPath);yield*await this.#callImplMethod("list",dirPath);}
async*walk(dirPath,{directoryFilter=()=>true,entryFilter=()=>true}={},){assertValidFileOrDirPath(dirPath);this.#log("walk",dirPath,{directoryFilter,entryFilter});const walk=async function*(dirPath,{directoryFilter,entryFilter,parentPath="",depth=1},){let dirEntries;try{dirEntries=await this.#callImplMethodWithoutLog("list",dirPath,);}catch(error){if(error.code==="ENOENT"){return;}
throw error;}
for await(const listEntry of dirEntries){const walkEntry={path:listEntry.name,depth,...listEntry,};if(parentPath){walkEntry.path=`${parentPath}/${walkEntry.path}`;}
let shouldEmitEntry=entryFilter(walkEntry);if(shouldEmitEntry.then){shouldEmitEntry=await shouldEmitEntry;}
if(shouldEmitEntry){yield walkEntry;}
if(listEntry.isDirectory){let shouldWalkDirectory=directoryFilter(walkEntry);if(shouldWalkDirectory.then){shouldWalkDirectory=await shouldWalkDirectory;}
if(!shouldWalkDirectory){continue;}
const directoryPath=dirPath instanceof URL?new URL(listEntry.name,dirPath.href.endsWith("/")?dirPath.href:`${dirPath.href}/`,):`${dirPath.endsWith("/") ? dirPath : `${dirPath}/`}${listEntry.name}`;yield*walk(directoryPath,{directoryFilter,entryFilter,parentPath:walkEntry.path,depth:depth+1,});}}}.bind(this);yield*walk(dirPath,{directoryFilter,entryFilter});}
async size(filePath){assertValidFileOrDirPath(filePath);return this.#callImplMethod("size",filePath);}
async lastModified(fileOrDirPath){assertValidFileOrDirPath(fileOrDirPath);return this.#callImplMethod("lastModified",fileOrDirPath);}
async copy(source,destination){assertValidFileOrDirPath(source);assertValidFileOrDirPath(destination);return this.#callImplMethod("copy",source,destination);}
async copyAll(source,destination){assertValidFileOrDirPath(source);assertValidFileOrDirPath(destination);return this.#callImplMethod("copyAll",source,destination);}
async move(source,destination){assertValidFileOrDirPath(source);assertValidFileOrDirPath(destination);return this.#callImplMethod("move",source,destination);}
async moveAll(source,destination){assertValidFileOrDirPath(source);assertValidFileOrDirPath(destination);return this.#callImplMethod("moveAll",source,destination);}}